      await pool.query(
        'DELETE FROM migrations WHERE name = $1',
        [lastMigration]
      );

      logger.info(`Rolled back migration: ${lastMigration}`);
    }
  } catch (error) {
    logger.error('Migration rollback failed:', error);
    throw error;
  }
